import React, { useState } from 'react';
import './index.css';

const API_BASE = 'http://127.0.0.1:8000';

const genres = [
  { id: 'rock', name: 'Rock' },
  { id: 'pop', name: 'Pop' },
  { id: 'jazz', name: 'Jazz' },
  { id: 'classical', name: 'Classical' },
  { id: 'hip-hop', name: 'Hip-Hop' },
  { id: 'electronic', name: 'Electronic' },
  { id: 'indie', name: 'Indie' },
  { id: 'r&b', name: 'R&B' },
  { id: 'country', name: 'Country' },
  { id: 'metal', name: 'Metal' },
  { id: 'latin', name: 'Latin' },
  { id: 'folk', name: 'Folk' },
];

const moods = [
  { id: 'happy', name: 'Happy', emoji: '☀' },
  { id: 'energetic', name: 'Energetic', emoji: '⚡' },
  { id: 'relaxing', name: 'Relaxing', emoji: '🌊' },
  { id: 'romantic', name: 'Romantic', emoji: '💜' },
  { id: 'sad', name: 'Sad', emoji: '🌧' },
  { id: 'focus', name: 'Focus', emoji: '🎯' },
  { id: 'party', name: 'Party', emoji: '🎉' },
  { id: 'workout', name: 'Workout', emoji: '💪' },
  { id: 'chill', name: 'Chill', emoji: '😌' },
];

const suggestedArtists = [
  'Taylor Swift',
  'Drake',
  'The Weeknd',
  'Billie Eilish',
];

function App() {
  const [selectedGenre, setSelectedGenre] = useState(null);
  const [selectedMood, setSelectedMood] = useState(null);
  const [selectedArtist, setSelectedArtist] = useState('');
  const [songCount, setSongCount] = useState(10);
  const [playlist, setPlaylist] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [showEmpty, setShowEmpty] = useState(true);

  const handleGenerate = async () => {
    if (!selectedGenre && !selectedMood && !selectedArtist) {
      setError('Please select at least one preference');
      return;
    }

    setLoading(true);
    setError(null);
    setShowEmpty(false);
    setPlaylist([]);

    try {
      let endpoint = '/custom';
      const params = new URLSearchParams();

      if (selectedGenre) params.append('genre', selectedGenre);
      if (selectedMood) params.append('mood', selectedMood);
      if (selectedArtist) params.append('artist', selectedArtist);
      params.append('limit', songCount);

      const response = await fetch(`${API_BASE}${endpoint}?${params}`);

      if (!response.ok) {
        throw new Error('Server error: ' + response.status);
      }

      const data = await response.json();

      if (data.error) {
        throw new Error(data.error);
      }

      if (!data.playlist || data.playlist.length === 0) {
        throw new Error('No songs found');
      }

      setPlaylist(data.playlist);
    } catch (err) {
      console.error('Error:', err);
      setError(err.message || 'Failed to generate playlist');
    } finally {
      setLoading(false);
    }
  };

  const playPreview = (url) => {
    const audio = new Audio(url);
    audio.play().catch(() => {});
  };

  const capitalizeFirst = (str) => {
    if (!str) return '';
    return str.charAt(0).toUpperCase() + str.slice(1);
  };

  const getResultsTitle = () => {
    if (selectedMood) return capitalizeFirst(selectedMood) + ' Vibes';
    if (selectedGenre) return capitalizeFirst(selectedGenre) + ' Mix';
    return 'Your Playlist';
  };

  const defaultArtwork = 'data:image/svg+xml,%3Csvg xmlns=%22http://www.w3.org/2000/svg%22 width=%22100%22 height=%22100%22%3E%3Crect fill=%22%231a1a24%22 width=%22100%22 height=%22100%22/%3E%3Ctext x=%2250%22 y=%2250%22 text-anchor=%22middle%22 dy=%22.3em%22 fill=%22%23606070%22 font-size=%2240%22%3E%E2%99%AA%3C/text%3E%3C/svg%3E';

  return (
    <div className="App">
      <div className="background-effects">
        <div className="gradient-orb orb-1"></div>
        <div className="gradient-orb orb-2"></div>
        <div className="gradient-orb orb-3"></div>
      </div>

      <header className="header">
        <div className="logo">
          <svg className="logo-icon" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
            <circle cx="12" cy="12" r="10" stroke="url(%23gradient)" strokeWidth="2"/>
            <circle cx="12" cy="12" r="3" fill="url(%23gradient)"/>
            <defs>
              <linearGradient id="gradient" x1="0" y1="0" x2="24" y2="24">
                <stop offset="0%" stopColor="%23ff6b9d"/>
                <stop offset="50%" stopColor="%23c44cff"/>
                <stop offset="100%" stopColor="%236bfff0"/>
              </linearGradient>
            </defs>
          </svg>
          <span className="logo-text">VibeFlow</span>
        </div>
        <p className="tagline">Generate playlists based on your mood, genre and favorite artists</p>
      </header>

      <main className="main-container">
        <section className="generator-section">
          <h2 className="section-title">Create Your Perfect Playlist</h2>
          
          <div className="input-grid">
            <div className="input-group">
              <label className="input-label">Select Genre</label>
              <div className="genre-grid">
                {genres.map((genre) => (
                  <button
                    key={genre.id}
                    className={`genre-btn ${selectedGenre === genre.id ? 'active' : ''}`}
                    onClick={() => setSelectedGenre(selectedGenre === genre.id ? null : genre.id)}
                  >
                    {genre.name}
                  </button>
                ))}
              </div>
            </div>

            <div className="input-group">
              <label className="input-label">Select Mood</label>
              <div className="mood-grid">
                {moods.map((mood) => (
                  <button
                    key={mood.id}
                    className={`mood-btn ${selectedMood === mood.id ? 'active' : ''}`}
                    onClick={() => setSelectedMood(selectedMood === mood.id ? null : mood.id)}
                  >
                    <span className="mood-emoji">{mood.emoji}</span>
                    {mood.name}
                  </button>
                ))}
              </div>
            </div>

            <div className="input-group full-width">
              <label className="input-label">Favorite Artist (Optional)</label>
              <div className="artist-input-wrapper">
                <input
                  type="text"
                  className="artist-input"
                  placeholder="e.g., Taylor Swift, Ed Sheeran..."
                  value={selectedArtist}
                  onChange={(e) => setSelectedArtist(e.target.value)}
                />
                <div className="suggested-artists">
                  <span className="suggest-label">Quick add:</span>
                  {suggestedArtists.map((artist) => (
                    <button
                      key={artist}
                      className="suggest-btn"
                      onClick={() => setSelectedArtist(artist)}
                    >
                      {artist}
                    </button>
                  ))}
                </div>
              </div>
            </div>
          </div>

          <div className="generate-section">
            <button
              className="generate-btn"
              onClick={handleGenerate}
              disabled={loading}
            >
              <span className="btn-text">{loading ? 'Generating...' : 'Generate Playlist'}</span>
            </button>
            <div className="playlist-count">
              <label>Songs:</label>
              <input
                type="range"
                min="5"
                max="25"
                value={songCount}
                onChange={(e) => setSongCount(e.target.value)}
                className="count-slider"
              />
              <span className="count-value">{songCount}</span>
            </div>
          </div>
        </section>

        <section className="results-section">
          {playlist.length > 0 ? (
            <div className="results-content">
              <div className="results-header">
                <h3 className="results-title">{getResultsTitle()}</h3>
                <div className="playlist-tags">
                  {selectedMood && <span className="playlist-tag">{selectedMood}</span>}
                  {selectedGenre && <span className="playlist-tag">{selectedGenre}</span>}
                  {selectedArtist && <span className="playlist-tag">{selectedArtist}</span>}
                </div>
              </div>
              
              <div className="songs-container">
                {playlist.map((song, index) => (
                  <div
                    key={index}
                    className="song-card"
                    style={{ animationDelay: (index * 0.05) + 's' }}
                  >
                    <span className="song-number">{index + 1}</span>
                    <img
                      src={song.artwork || defaultArtwork}
                      alt={song.title}
                      className="song-artwork"
                      onError={(e) => { e.target.src = defaultArtwork; }}
                    />
                    <div className="song-info">
                      <div className="song-title">{song.title || 'Unknown Title'}</div>
                      <div className="song-artist">{song.artist || 'Unknown Artist'}</div>
                    </div>
                    <span className="song-genre">{song.genre || 'Music'}</span>
                    {song.preview_url && (
                      <button
                        className="play-preview"
                        onClick={() => playPreview(song.preview_url)}
                      >
                        <svg viewBox="0 0 24 24">
                          <path d="M8 5v14l11-7z"/>
                        </svg>
                      </button>
                    )}
                  </div>
                ))}
              </div>
            </div>
          ) : null}

          <div className={`loading-spinner ${loading ? 'active' : ''}`}>
            <div className="spinner"></div>
            <p>Finding your perfect songs...</p>
          </div>

          <div className={`empty-state ${showEmpty && !loading && !error ? 'active' : ''}`}>
            <p>Select your preferences and hit generate!</p>
          </div>

          <div className={`error-state ${error ? 'active' : ''}`}>
            <p>{error}</p>
          </div>
        </section>
      </main>

      <footer className="footer">
        <p>Powered by iTunes API - Built with React and FastAPI</p>
      </footer>
    </div>
  );
}

export default App;
